/**
 * Cryptography Module Integration Tests
 * Tests for all crypto algorithms: hashing, encryption, key derivation, certificates, key management
 */

import { Hasher } from '../src/crypto/hashing';
import { AESEncryption } from '../src/crypto/symmetric';
import { RSAEncryption } from '../src/crypto/asymmetric';
import { HMACGenerator } from '../src/crypto/hmac';
import { KeyDerivation } from '../src/crypto/key-derivation';
import { CertificateManager } from '../src/crypto/certificates';
import { KeyManager } from '../src/crypto/key-management';
import { CryptoError } from '../src/crypto/types';

describe('Cryptography Integration Tests', () => {
  describe('Hashing (MD5, SHA1, SHA256, SHA512)', () => {
    test('SHA256 hashing', () => {
      const data = 'Hello, FreeLang!';
      const result = Hasher.hash(data, 'SHA256');

      expect(result).toHaveProperty('algorithm', 'SHA256');
      expect(result).toHaveProperty('hash');
      expect(result.hash).toHaveLength(64); // SHA256 = 64 hex chars
      expect(result).toHaveProperty('length', 32); // 32 bytes
      expect(result).toHaveProperty('timestamp');
    });

    test('SHA512 hashing', () => {
      const data = 'Test data';
      const result = Hasher.hash(data, 'SHA512');

      expect(result.algorithm).toBe('SHA512');
      expect(result.hash).toHaveLength(128); // SHA512 = 128 hex chars
      expect(result.length).toBe(64); // 64 bytes
    });

    test('Hash with salt', () => {
      const data = 'password';
      const salt = Hasher.generateSalt(32);
      const result = Hasher.hashWithSalt(data, salt);

      expect(result).toHaveProperty('algorithm');
      expect(result).toHaveProperty('hash');
      expect(salt).toHaveLength(64); // 32 bytes = 64 hex chars
    });

    test('Hash verification', () => {
      const data = 'test data';
      const result = Hasher.hash(data);

      expect(Hasher.verify(data, result.hash)).toBe(true);
      expect(Hasher.verify('wrong data', result.hash)).toBe(false);
    });

    test('Multiple algorithms', () => {
      const data = 'test';
      const algorithms = ['MD5', 'SHA1', 'SHA256', 'SHA512'] as const;

      algorithms.forEach(algo => {
        const result = Hasher.hash(data, algo);
        expect(result.algorithm).toBe(algo);
        expect(result.hash).toBeDefined();
      });
    });
  });

  describe('Symmetric Encryption (AES-256)', () => {
    test('Generate AES key and IV', () => {
      const key = AESEncryption.generateKey(256);
      const iv = AESEncryption.generateIV(16);

      expect(key).toBeDefined();
      expect(iv).toBeDefined();
      expect(key.length).toBeGreaterThan(0);
    });

    test('AES-256-GCM encryption and decryption', () => {
      const plaintext = 'Secret message for FreeLang';
      const key = AESEncryption.generateKey(256);

      const encrypted = AESEncryption.encrypt(plaintext, key);

      expect(encrypted).toHaveProperty('ciphertext');
      expect(encrypted).toHaveProperty('iv');
      expect(encrypted).toHaveProperty('algorithm', 'AES-256-GCM');
      expect(encrypted).toHaveProperty('tag'); // GCM produces auth tag

      const decrypted = AESEncryption.decrypt(encrypted, key);

      expect(decrypted.plaintext).toBe(plaintext);
      expect(decrypted.verified).toBe(true);
    });

    test('Key derivation from password', () => {
      const password = 'MySecurePassword123!';
      const salt = AESEncryption.generateIV(16);

      const derived = AESEncryption.deriveKeyFromPassword(password, salt, 100000);

      expect(derived).toBeDefined();

