/**
 * Hashing Functions
 * MD5, SHA1, SHA256, SHA512
 */

import * as crypto from 'crypto';
import { HashAlgorithm, HashResult, CryptoError } from './types';

export class Hasher {
  /**
   * Hash data using specified algorithm
   */
  static hash(data: string, algorithm: HashAlgorithm = 'SHA256'): HashResult {
    try {
      const normalizedAlgo = this.normalizeAlgorithm(algorithm);
      const hash = crypto.createHash(normalizedAlgo).update(data).digest('hex');

      return {
        algorithm,
        hash,
        length: Buffer.from(hash, 'hex').length,
        timestamp: Date.now()
      };
    } catch (error) {
      throw new CryptoError('hash', algorithm, String(error));
    }
  }

  /**
   * Hash data with salt (for password hashing prep)
   */
  static hashWithSalt(
    data: string,
    salt: string,
    algorithm: HashAlgorithm = 'SHA256'
  ): HashResult {
    const combined = data + salt;
    return this.hash(combined, algorithm);
  }

  /**
   * Verify hash
   */
  static verify(data: string, hash: string, algorithm: HashAlgorithm = 'SHA256'): boolean {
    const result = this.hash(data, algorithm);
    return this.constantTimeCompare(result.hash, hash);
  }

  /**
   * Generate random salt
   */
  static generateSalt(length: number = 32): string {
    return crypto.randomBytes(length).toString('hex');
  }

  /**
   * Normalize algorithm names
   */
  private static normalizeAlgorithm(algo: HashAlgorithm): string {
    const mapping: Record<HashAlgorithm, string> = {
      MD5: 'md5',
      SHA1: 'sha1',
      SHA256: 'sha256',
      SHA512: 'sha512'
    };
    return mapping[algo];
  }

  /**
   * Constant-time comparison (prevent timing attacks)
   */
  private static constantTimeCompare(a: string, b: string): boolean {
    if (a.length !== b.length) return false;
    let result = 0;
    for (let i = 0; i < a.length; i++) {
      result |= a.charCodeAt(i) ^ b.charCodeAt(i);
    }
    return result === 0;
  }
}

