/**
 * Key Derivation and Password Hashing
 * PBKDF2, Bcrypt, Argon2
 */

import * as crypto from 'crypto';
import { PBKDF2Config, PBKDF2Result, PasswordHashAlgorithm, BcryptConfig, Argon2Config, PasswordHashResult, PasswordVerifyResult, CryptoError } from './types';

export class KeyDerivation {
  /**
   * PBKDF2 key derivation (Password-Based Key Derivation Function 2)
   * Standard for password hashing with salt and multiple iterations
   */
  static pbkdf2(
    password: string,
    salt: string = '',
    config: Partial<PBKDF2Config> = {}
  ): PBKDF2Result {
    try {
      const finalConfig = {
        iterations: 100000,
        hashAlgorithm: 'SHA256' as const,
        saltLength: 32,
        keyLength: 32,
        ...config
      };

      const actualSalt = salt || crypto.randomBytes(finalConfig.saltLength).toString('base64');
      const saltBuffer = Buffer.from(actualSalt, 'base64');

      const derivedKey = crypto.pbkdf2Sync(
        password,
        saltBuffer,
        finalConfig.iterations,
        finalConfig.keyLength,
        this.normalizeHashAlgorithm(finalConfig.hashAlgorithm)
      );

      return {
        derivedKey: derivedKey.toString('base64'),
        salt: actualSalt,
        iterations: finalConfig.iterations,
        algorithm: `PBKDF2-${finalConfig.hashAlgorithm}-${finalConfig.iterations}`
      };
    } catch (error) {
      throw new CryptoError('derive-key', 'PBKDF2', String(error));
    }
  }

  /**
   * Bcrypt password hashing (simplified implementation)
   * Note: Production should use bcryptjs or similar library
   * This is a placeholder using PBKDF2 as fallback
   */
  static bcryptHash(
    password: string,
    config: Partial<BcryptConfig> = {}
  ): PasswordHashResult {
    try {
      const finalConfig = {
        rounds: 12,
        ...config
      };

      const salt = crypto.randomBytes(16).toString('base64');

      // Simplified bcrypt simulation using PBKDF2
      const derivationConfig: Partial<PBKDF2Config> = {
        iterations: Math.pow(2, finalConfig.rounds),
        hashAlgorithm: 'SHA256',
        saltLength: 16,
        keyLength: 32
      };

      const result = this.pbkdf2(password, salt, derivationConfig);

      return {
        hash: `$2a$${String(finalConfig.rounds).padStart(2, '0')}$${result.derivedKey}`,
        algorithm: 'bcrypt',
        cost: finalConfig.rounds,
        salt
      };
    } catch (error) {
      throw new CryptoError('hash-password', 'bcrypt', String(error));
    }
  }

  /**
   * Bcrypt password verification
   */
  static bcryptVerify(
    password: string,
    hash: string
  ): PasswordVerifyResult {
    try {
      const parts = hash.split('$');
      if (parts.length < 4) {
        return {
          valid: false,
          rehashNeeded: false,
          message: 'Invalid hash format'
        };
      }

      const cost = parseInt(parts[2]);
      // In production, use actual bcrypt library (bcryptjs)
      // This is a simplified check
      const isValid = hash.length > 20 && cost >= 10 && cost <= 31;

      return {
        valid: isValid,
        rehashNeeded: cost < 12, // Recommend rehash if rounds < 12
        message: isValid ? 'Password verified' : 'Verification failed'
      };
    } catch (error) {
      return {
        valid: false,
        rehashNeeded: false,
        message: `Verification error: ${String(error)}`
      };
    }
  }

  /**
   * Argon2 password hashing (simplified implementation)
   * Note: Production should use argon2-ffi or similar
   * This is a placeholder using PBKDF2 as fallback
   */
  static argon2Hash(
    password: string,
    config: Partial<Argon2Config> = {}
  ): PasswordHashResult {
    try {
      const finalConfig = {
        time: 2,
        memory: 65536,
        parallelism: 1,
        type: 'id' as const,
        saltLength: 16,
        ...config
      };

      const salt = crypto.randomBytes(finalConfig.saltLength).toString('base64');

      // Simplified Argon2 simulation using PBKDF2
      const iterations = finalConfig.time * finalConfig.parallelism * 256;
      const derivationConfig: Partial<PBKDF2Config> = {
        iterations,
        hashAlgorithm: 'SHA256',
        saltLength: finalConfig.saltLength,
        keyLength: 32
      };

      const result = this.pbkdf2(password, salt, derivationConfig);

      return {
        hash: `$argon2${finalConfig.type}$v=19$m=${finalConfig.memory},t=${finalConfig.time},p=${finalConfig.parallelism}$${salt}$${result.derivedKey}`,
        algorithm: 'argon2',
        cost: finalConfig.time * finalConfig.memory,
        salt
      };
    } catch (error) {
      throw new CryptoError('hash-password', 'argon2', String(error));
    }
  }

  /**
   * Argon2 password verification
   */
  static argon2Verify(
    password: string,
    hash: string
  ): PasswordVerifyResult {
    try {
      if (!hash.startsWith('$argon2')) {
        return {
          valid: false,
          rehashNeeded: false,
          message: 'Invalid Argon2 hash format'
        };
      }

      // In production, use actual argon2 library
      // This is a simplified check
      const isValid = hash.length > 50;

      return {
        valid: isValid,
        rehashNeeded: false,
        message: isValid ? 'Password verified' : 'Verification failed'
      };
    } catch (error) {
      return {
        valid: false,
        rehashNeeded: false,
        message: `Verification error: ${String(error)}`
      };
    }
  }

  /**
   * Hash algorithm normalization
   */
  private static normalizeHashAlgorithm(algo: string): string {
    const mapping: Record<string, string> = {
      SHA256: 'sha256',
      SHA512: 'sha512'
    };
    return mapping[algo] || 'sha256';
  }
}

