  } as const;

  /**
   * PBKDF2 key derivation (Password-Based Key Derivation Function 2)
   * Standard for password hashing with salt and multiple iterations
   */
  static pbkdf2(
    password: string,
    salt: string = '',
    config: Partial<PBKDF2Config> = {}
  ): PBKDF2Result {
