      let saltBuffer: Buffer;
      let actualSalt: string;

      if (salt) {
        saltBuffer = Buffer.from(salt, 'base64');
        actualSalt = salt;
      } else {
        // Generate salt as Buffer directly (skip base64 conversion)
        saltBuffer = crypto.randomBytes(finalConfig.saltLength);
        actualSalt = saltBuffer.toString('base64');
      }

