        saltBuffer,
        finalConfig.iterations,
        finalConfig.keyLength,
        normalizedHashAlgo
      );

      return {
        derivedKey: derivedKey.toString('base64'),
        salt: actualSalt,
        iterations: finalConfig.iterations,
        algorithm: `PBKDF2-${finalConfig.hashAlgorithm}-${finalConfig.iterations}`
      };
    } catch (error) {
      throw new CryptoError('derive-key', 'PBKDF2', String(error));
    }
