        hashAlgorithm: 'SHA256',
        saltLength: 16,
        keyLength: 32
      };

      const result = this.pbkdf2(password, salt, derivationConfig);

      return {
        hash: `$2a$${String(finalConfig.rounds).padStart(2, '0')}$${result.derivedKey}`,
