// Execution Context
// Manages scope, variables, and call stack

use std::collections::HashMap;
use crate::core::Value;
use std::time::Instant;

/// Call frame for function calls
#[derive(Clone, Debug)]
pub struct CallFrame {
    pub name: String,
    pub locals: HashMap<String, Value>,
    pub created_at: Instant,
}

impl CallFrame {
    /// Create new call frame
    pub fn new(name: String) -> Self {
        CallFrame {
            name,
            locals: HashMap::new(),
            created_at: Instant::now(),
        }
    }

    /// Get variable
    pub fn get(&self, name: &str) -> Option<Value> {
        self.locals.get(name).cloned()
    }

    /// Set variable
    pub fn set(&mut self, name: String, value: Value) {
        self.locals.insert(name, value);
    }
}

/// Execution context for FreeLang programs
pub struct ExecutionContext {
    globals: HashMap<String, Value>,
    call_stack: Vec<CallFrame>,
    variable_count: u64,
}

impl ExecutionContext {
    /// Create new context
    pub fn new() -> Self {
        ExecutionContext {
            globals: HashMap::new(),
            call_stack: vec![CallFrame::new("global".to_string())],
            variable_count: 0,
        }
    }

    /// Set global variable
    pub fn set_global(&mut self, name: String, value: Value) {
        self.globals.insert(name, value);
        self.variable_count += 1;
    }

    /// Get global variable
    pub fn get_global(&self, name: &str) -> Option<Value> {
        self.globals.get(name).cloned()
    }

    /// Push new call frame
    pub fn push_frame(&mut self, name: String) {
        self.call_stack.push(CallFrame::new(name));
    }

    /// Pop call frame
    pub fn pop_frame(&mut self) -> Option<CallFrame> {
        if self.call_stack.len() > 1 {
            self.call_stack.pop()
        } else {
            None
        }
    }

    /// Get current frame
    pub fn current_frame(&mut self) -> Option<&mut CallFrame> {
        self.call_stack.last_mut()
    }

    /// Get current frame (immutable)
    pub fn current_frame_ref(&self) -> Option<&CallFrame> {
        self.call_stack.last()
    }

