    }

    let path = args[0].to_string();
    match std::fs::create_dir_all(&path) {
        Ok(_) => Ok(Value::Null),
        Err(e) => Err(format!("Cannot create directory: {}", e))
    }
}

/// Print to stderr
pub fn eprint(args: Vec<Value>) -> Result<Value, String> {
    for arg in args {
        eprint!("{}", arg);
    }
    Ok(Value::Null)
}

/// Print to stderr with newline
