    if args.is_empty() {
        return Err("min requires at least 1 argument".to_string());
    }

    let mut min_val = args[0].to_number();
    for arg in &args[1..] {
        let val = arg.to_number();
        if val < min_val {
            min_val = val;
        }
    }
    Ok(Value::Number(min_val))
