        use std::time::Instant;
        let start = Instant::now();
        let result = sleep(vec![Value::Number(10.0)]); // Sleep 10ms
        let elapsed = start.elapsed().as_millis();

        assert!(result.is_ok());
        assert!(elapsed >= 10); // Should take at least 10ms
    }
}

