        let result = time(vec![]);
        assert!(result.is_ok());
        let timestamp = result.unwrap().to_number();
        assert!(timestamp > 0.0);
    }

    #[test]
    fn test_time_ms() {
        let result = time_ms(vec![]);
        assert!(result.is_ok());
