        assert_eq!(stack.depth(), 2);
        assert_eq!(stack.total_variables(), 1);

        stack.clear();

        assert_eq!(stack.depth(), 1);
        assert_eq!(stack.total_variables(), 0);
        assert_eq!(stack.call_count(), 0);
    }
}

