    use std::time::Instant;

    // Benchmark: 100,000 calls with 10 unique function names
    let unique_names = vec!["func_0", "func_1", "func_2", "func_3", "func_4",
                            "func_5", "func_6", "func_7", "func_8", "func_9"];

